create table dirkspzm32.isi_arbeitsplatz_param (
    modul_name           varchar2(20 char) not null enable,
    modul_funktion       varchar2(50 char) not null enable,
    modul_parameter      varchar2(300 char),
    modul_beschreibung   varchar2(150 char),
    modul_lookup_report  varchar2(100 char),
    modul_parameter_lang varchar2(120 char),
    modul_param_typ      number(*, 0) default 1 not null enable
);

alter table dirkspzm32.isi_arbeitsplatz_param
    add constraint pk_isi_arbeitsplatz_param primary key ( modul_name,
                                                           modul_funktion )
        using index enable;


